// Does the whole call from inside a Code node using this.helpers.httpRequest,
// which returns a clean decompressed body (avoids the HttpRequestV3 'toText'
// circular-socket bug in some n8n versions).

const input = $input.first().json;

// --- parse session.json ---
let session;
try {
  session = typeof input.sessionJson === 'string' ? JSON.parse(input.sessionJson) : input.sessionJson;
} catch (e) {
  throw new Error('sessionJson is not valid JSON. Paste the full contents of session.json.');
}
if (!session.cookies || !session.token) {
  throw new Error('session.json missing cookies or token. Re-run login.');
}

const cookie = session.cookies.map(c => `${c.name}=${c.value}`).join('; ');
const token = session.token;
const base = session.portalUrl || 'https://integration.commonwellalliance.lkopera.com/';
const url = base.replace(/\/$/, '') + '/TransactionLogs/BindTransactionLogs';

// --- build form body ---
const enc = encodeURIComponent;
const fields = {
  sort: 'transactionId-asc',
  page: String(input.page || 1),
  pageSize: String(input.pageSize || 20),
  group: '',
  filter: '',
  Status: input.status || 'All',
  FromDate: input.fromDate || '',
  ToDate: input.toDate || '',
  organizationId: '',
  MemberId: '',
  TransactionType: '',
  TransactionId: '',
  before: '',
  after: '',
  __RequestVerificationToken: token
};
const body = Object.keys(fields).map(k => `${enc(k)}=${enc(fields[k])}`).join('&');

// --- make the request ---
let responseBody;
try {
  responseBody = await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: {
      'Cookie': cookie,
      'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
      'X-Requested-With': 'XMLHttpRequest',
      'Accept': '*/*',
      'Origin': base.replace(/\/$/, ''),
      'Referer': base.replace(/\/$/, '') + '/TransactionLogs/index'
    },
    body,
    json: false
  });
} catch (err) {
  throw new Error('HTTP request failed: ' + (err.message || err));
}

// responseBody is a string (or already-parsed object)
let resp = responseBody;
if (typeof resp === 'string') {
  let text = resp.trim();
  if (text.startsWith('<')) {
    throw new Error('Got HTML instead of JSON — session expired. Re-run login and paste a fresh session.json.');
  }
  resp = JSON.parse(text);
}

// extract rows
let rows;
if (Array.isArray(resp)) rows = resp;
else if (resp && resp.Data) rows = resp.Data;
else if (resp && resp.data) rows = resp.data;
else if (resp && resp.rows) rows = resp.rows;
else rows = [];

const total = (resp && (resp.Total || resp.total)) || rows.length;
return [{ json: { rows, count: rows.length, total } }];
